+{
+  {
+    const bool expectation = true;
+    expect_fixed<rosidl_generator_cpp::msg::Empty, expectation>::type x = expectation;
+    printf("Test passed: type Empty::has_fixed_size == %d\n", x);
+  }
+
+  {
